// Scroll the grid to the very bottom, then check what's at the bottom
return page.evaluate(async () => {
  const container = document.querySelector('.sv-grid-container')
  if (container) {
    container.scrollTop = container.scrollHeight
    await new Promise(r => setTimeout(r, 200))
  }

  const shell = document.querySelector('.sv-grid-shell')
  const shellRect = shell?.getBoundingClientRect()

  // Inspect all absolutely positioned elements at the bottom of the shell
  const shellEl = shell as HTMLElement
  const allChildren = shellEl ? Array.from(shellEl.querySelectorAll('*')) : []
  const bottomEls: any[] = []

  for (const el of allChildren) {
    const rect = el.getBoundingClientRect()
    if (Math.abs(rect.bottom - (shellRect?.bottom ?? 0)) < 20 && rect.height > 0 && rect.height < 40) {
      const cs = window.getComputedStyle(el as Element)
      bottomEls.push({
        tag: (el as Element).tagName,
        class: (el as Element).className.substring(0, 80),
        bg: cs.backgroundColor,
        rect: { top: rect.top, bottom: rect.bottom, height: rect.height, width: rect.width }
      })
    }
  }

  // Also check what's right at the bottom edge (y = shellRect.bottom - 1 to bottom - 8)
  const bottomInspect: any[] = []
  for (let y = (shellRect?.bottom ?? 0) - 1; y > (shellRect?.bottom ?? 0) - 20; y -= 2) {
